#include <stdio.h>
#include <string.h>

int isPal(const char *s, int l, int r) {
    while (l < r) {
        if (s[l] != s[r]) return 0;
        l++; r--;
    }
    return 1;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int N = strlen(S);
        int l = 0, r = N - 1;
        while (l < r && S[l] == S[r]) { l++; r--; }
        if (l >= r) {
            printf("%d\n", N + 1);
            continue;
        }
        int ans = 0;
        if (isPal(S, l + 1, r)) ans++;          // insert before l
        if (isPal(S, l, r - 1)) ans++;          // insert after r
        printf("%d\n", ans);
    }
    return 0;
}

