#include <bits/stdc++.h>
using namespace std;

bool isPal(const string &s, int l, int r) {
    while (l < r) {
        if (s[l] != s[r]) return false;
        ++l; --r;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        string S; cin >> S;
        int N = S.size();
        int l = 0, r = N - 1;
        while (l < r && S[l] == S[r]) { ++l; --r; }
        if (l >= r) {
            cout << N + 1 << '\n';
            continue;
        }
        int ans = 0;
        if (isPal(S, l + 1, r)) ++ans; // insert at position l
        if (isPal(S, l, r - 1)) ++ans; // insert at position r+1
        cout << ans << '\n';
    }
    return 0;
}

