import sys

def is_pal(s, l, r):
    while l < r:
        if s[l] != s[r]:
            return False
        l += 1
        r -= 1
    return True

def solve():
    data = sys.stdin.read().splitlines()
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        s = data[idx].strip()
        idx += 1
        n = len(s)
        l, r = 0, n - 1
        while l < r and s[l] == s[r]:
            l += 1
            r -= 1
        if l >= r:
            out.append(str(n + 1))
            continue
        ans = 0
        if is_pal(s, l + 1, r):
            ans += 1  # insert at position l
        if is_pal(s, l, r - 1):
            ans += 1  # insert at position r+1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

